import{_ as i,a as n,b as e,o as a}from"./app-Bo52SUcV.js";const s={};function t(r,l){return a(),n("div",null,[...l[0]||(l[0]=[e('<h1 id="常见问题" tabindex="-1"><a class="header-anchor" href="#常见问题"><span>常见问题</span></a></h1><h2 id="安装问题" tabindex="-1"><a class="header-anchor" href="#安装问题"><span>安装问题</span></a></h2><h3 id="提示缺少-net-runtime" tabindex="-1"><a class="header-anchor" href="#提示缺少-net-runtime"><span>提示缺少 .NET Runtime</span></a></h3><p><strong>问题：</strong> 启动应用时提示缺少 .NET 8.0 Runtime。</p><p><strong>解决方案：</strong></p><ol><li>访问 <a href="https://dotnet.microsoft.com/download/dotnet/8.0" target="_blank" rel="noopener noreferrer">.NET 下载页面</a></li><li>下载并安装 .NET 8.0 Desktop Runtime</li><li>重启应用</li></ol><h3 id="安装失败" tabindex="-1"><a class="header-anchor" href="#安装失败"><span>安装失败</span></a></h3><p><strong>问题：</strong> 安装程序无法完成安装。</p><p><strong>解决方案：</strong></p><ol><li>以管理员身份运行安装程序</li><li>检查是否有足够的磁盘空间（至少 100 MB）</li><li>关闭杀毒软件后重试</li><li>检查 Windows 更新是否完成</li></ol><h2 id="使用问题" tabindex="-1"><a class="header-anchor" href="#使用问题"><span>使用问题</span></a></h2><h3 id="无法打开-pdf-文件" tabindex="-1"><a class="header-anchor" href="#无法打开-pdf-文件"><span>无法打开 PDF 文件</span></a></h3><p><strong>问题：</strong> 点击&quot;打开 PDF&quot;后没有反应或提示错误。</p><p><strong>可能原因：</strong></p><ul><li>PDF 文件损坏</li><li>PDF 文件被其他程序占用</li><li>文件路径包含特殊字符</li></ul><p><strong>解决方案：</strong></p><ol><li>尝试用其他 PDF 阅读器打开该文件，确认文件是否正常</li><li>关闭其他正在使用该 PDF 的程序</li><li>将文件移动到路径简单的文件夹（如桌面）</li><li>尝试打开其他 PDF 文件，确认是否是应用问题</li></ol><h3 id="批注无法保存" tabindex="-1"><a class="header-anchor" href="#批注无法保存"><span>批注无法保存</span></a></h3><p><strong>问题：</strong> 点击保存按钮后批注没有保存。</p><p><strong>可能原因：</strong></p><ul><li>没有写入权限</li><li>磁盘空间不足</li><li>文件路径过长</li></ul><p><strong>解决方案：</strong></p><ol><li>确认 PDF 文件所在文件夹有写入权限</li><li>检查磁盘空间是否充足</li><li>将 PDF 文件移动到路径较短的位置</li><li>以管理员身份运行应用</li></ol><h3 id="批注消失了" tabindex="-1"><a class="header-anchor" href="#批注消失了"><span>批注消失了</span></a></h3><p><strong>问题：</strong> 之前保存的批注打开后不见了。</p><p><strong>可能原因：</strong></p><ul><li>批注文件被删除或移动</li><li>批注文件损坏</li><li>PDF 文件被重命名或移动</li></ul><p><strong>解决方案：</strong></p><ol><li>检查 PDF 文件同目录下是否有 <code>.annotations</code> 文件</li><li>确认 PDF 文件名是否被修改</li><li>如果 PDF 文件被移动，将批注文件也移动到同一目录</li><li>如果批注文件损坏，可能无法恢复</li></ol><div class="hint-container tip"><p class="hint-container-title">提示</p><p>批注文件与 PDF 文件同名，扩展名为 <code>.annotations</code>。例如：</p><ul><li>PDF 文件：<code>lecture.pdf</code></li><li>批注文件：<code>lecture.annotations</code></li></ul></div><h3 id="窗口最大化后批注消失" tabindex="-1"><a class="header-anchor" href="#窗口最大化后批注消失"><span>窗口最大化后批注消失</span></a></h3><p><strong>问题：</strong> 切换窗口最大化/最小化时批注消失。</p><p><strong>解决方案：</strong> 此问题已在最新版本中修复。请更新到最新版本。</p><h3 id="绘制的线条不流畅" tabindex="-1"><a class="header-anchor" href="#绘制的线条不流畅"><span>绘制的线条不流畅</span></a></h3><p><strong>问题：</strong> 绘制的线条有锯齿或不平滑。</p><p><strong>解决方案：</strong></p><ol><li>在设置中启用&quot;平滑绘图&quot;选项</li><li>尝试调整画笔粗细</li><li>检查鼠标或触控板是否正常工作</li></ol><h3 id="橡皮擦无法擦除" tabindex="-1"><a class="header-anchor" href="#橡皮擦无法擦除"><span>橡皮擦无法擦除</span></a></h3><p><strong>问题：</strong> 使用橡皮擦工具无法擦除批注。</p><p><strong>可能原因：</strong></p><ul><li>橡皮大小太小</li><li>没有准确点击到笔画</li></ul><p><strong>解决方案：</strong></p><ol><li>增大橡皮大小</li><li>确保鼠标点击在笔画上</li><li>尝试多次擦除</li></ol><h2 id="性能问题" tabindex="-1"><a class="header-anchor" href="#性能问题"><span>性能问题</span></a></h2><h3 id="应用启动慢" tabindex="-1"><a class="header-anchor" href="#应用启动慢"><span>应用启动慢</span></a></h3><p><strong>问题：</strong> 应用启动需要很长时间。</p><p><strong>解决方案：</strong></p><ol><li>检查系统资源占用情况</li><li>关闭不必要的后台程序</li><li>重启计算机</li><li>检查杀毒软件是否在扫描应用</li></ol><h3 id="打开大型-pdf-很慢" tabindex="-1"><a class="header-anchor" href="#打开大型-pdf-很慢"><span>打开大型 PDF 很慢</span></a></h3><p><strong>问题：</strong> 打开页数较多的 PDF 文件需要很长时间。</p><p><strong>解决方案：</strong></p><ol><li>这是正常现象，应用需要渲染所有页面</li><li>等待渲染完成后即可正常使用</li><li>考虑将大型 PDF 拆分为多个小文件</li></ol><h3 id="缩放时卡顿" tabindex="-1"><a class="header-anchor" href="#缩放时卡顿"><span>缩放时卡顿</span></a></h3><p><strong>问题：</strong> 调整缩放级别时界面卡顿。</p><p><strong>解决方案：</strong></p><ol><li>减少批注数量</li><li>关闭其他占用资源的程序</li><li>升级计算机硬件（特别是内存）</li></ol><h2 id="数据问题" tabindex="-1"><a class="header-anchor" href="#数据问题"><span>数据问题</span></a></h2><h3 id="如何备份批注" tabindex="-1"><a class="header-anchor" href="#如何备份批注"><span>如何备份批注</span></a></h3><p><strong>问题：</strong> 如何备份我的批注数据？</p><p><strong>解决方案：</strong> 批注保存在 <code>.annotations</code> 文件中，与 PDF 文件同目录。备份方法：</p><ol><li>复制 PDF 文件和对应的 <code>.annotations</code> 文件</li><li>将两个文件保存到备份位置</li><li>恢复时将两个文件放回同一目录</li></ol><h3 id="如何迁移到新电脑" tabindex="-1"><a class="header-anchor" href="#如何迁移到新电脑"><span>如何迁移到新电脑</span></a></h3><p><strong>问题：</strong> 如何将批注数据迁移到新电脑？</p><p><strong>解决方案：</strong></p><ol><li>复制所有 PDF 文件和对应的 <code>.annotations</code> 文件</li><li>在新电脑上安装应用</li><li>将文件复制到新电脑</li><li>打开 PDF 文件，批注会自动加载</li></ol><h3 id="如何导出批注" tabindex="-1"><a class="header-anchor" href="#如何导出批注"><span>如何导出批注</span></a></h3><p><strong>问题：</strong> 如何将批注导出为图片或其他格式？</p><p><strong>解决方案：</strong> 当前版本不支持导出功能。临时方案：</p><ol><li>使用截图工具截取带批注的页面</li><li>或使用第三方 PDF 工具合并批注到 PDF</li></ol><div class="hint-container tip"><p class="hint-container-title">提示</p><p>我们计划在未来版本中添加导出功能。</p></div><h2 id="兼容性问题" tabindex="-1"><a class="header-anchor" href="#兼容性问题"><span>兼容性问题</span></a></h2><h3 id="支持哪些-pdf-版本" tabindex="-1"><a class="header-anchor" href="#支持哪些-pdf-版本"><span>支持哪些 PDF 版本</span></a></h3><p><strong>问题：</strong> 应用支持哪些版本的 PDF 文件？</p><p><strong>解答：</strong> 应用支持大多数标准 PDF 文件（PDF 1.0 - 2.0）。不支持：</p><ul><li>加密的 PDF 文件</li><li>需要密码的 PDF 文件</li><li>损坏的 PDF 文件</li></ul><h3 id="支持触摸屏吗" tabindex="-1"><a class="header-anchor" href="#支持触摸屏吗"><span>支持触摸屏吗</span></a></h3><p><strong>问题：</strong> 应用支持触摸屏设备吗？</p><p><strong>解答：</strong> 支持。可以使用触摸屏进行绘制和操作。但触控笔体验更好。</p><h3 id="支持触控笔吗" tabindex="-1"><a class="header-anchor" href="#支持触控笔吗"><span>支持触控笔吗</span></a></h3><p><strong>问题：</strong> 应用支持触控笔（如 Surface Pen）吗？</p><p><strong>解答：</strong> 支持。应用完全支持 Windows Ink 触控笔，可以获得更自然的书写体验。</p><h2 id="其他问题" tabindex="-1"><a class="header-anchor" href="#其他问题"><span>其他问题</span></a></h2><h3 id="如何反馈问题" tabindex="-1"><a class="header-anchor" href="#如何反馈问题"><span>如何反馈问题</span></a></h3><p><strong>问题：</strong> 发现 Bug 或有功能建议如何反馈？</p><p><strong>解决方案：</strong></p><ol><li>访问 <a href="https://github.com/LouisLu010/PdfTeachAnnotator/issues" target="_blank" rel="noopener noreferrer">GitHub Issues</a></li><li>搜索是否已有相同问题</li><li>如果没有，创建新的 Issue</li><li>详细描述问题或建议</li></ol><h3 id="如何获取更新" tabindex="-1"><a class="header-anchor" href="#如何获取更新"><span>如何获取更新</span></a></h3><p><strong>问题：</strong> 如何获取应用的最新版本？</p><p><strong>解决方案：</strong></p><ol><li>访问 <a href="https://github.com/LouisLu010/PdfTeachAnnotator/releases" target="_blank" rel="noopener noreferrer">GitHub Releases</a></li><li>下载最新版本的安装包</li><li>运行安装包覆盖安装</li></ol><div class="hint-container tip"><p class="hint-container-title">提示</p><p>未来版本将添加自动更新检查功能。</p></div><h3 id="应用是否收费" tabindex="-1"><a class="header-anchor" href="#应用是否收费"><span>应用是否收费</span></a></h3><p><strong>问题：</strong> 应用是免费的吗？</p><p><strong>解答：</strong> 是的，应用完全免费且开源（MIT License）。您可以：</p><ul><li>免费使用</li><li>查看源代码</li><li>修改和分发</li><li>用于商业用途</li></ul><h3 id="隐私和安全" tabindex="-1"><a class="header-anchor" href="#隐私和安全"><span>隐私和安全</span></a></h3><p><strong>问题：</strong> 应用会收集我的数据吗？</p><p><strong>解答：</strong> 不会。应用：</p><ul><li>不收集任何用户数据</li><li>不连接互联网</li><li>所有数据保存在本地</li><li>不包含任何追踪代码</li></ul><h3 id="如何卸载" tabindex="-1"><a class="header-anchor" href="#如何卸载"><span>如何卸载</span></a></h3><p><strong>问题：</strong> 如何完全卸载应用？</p><p><strong>解决方案：</strong></p><ol><li>打开 Windows 设置 → 应用 → 已安装的应用</li><li>找到&quot;PDF 教学批注工具&quot;</li><li>点击&quot;卸载&quot;</li><li>手动删除配置文件（可选）： <ul><li><code>%APPDATA%\\PdfTeachAnnotator\\</code></li></ul></li></ol><div class="hint-container warning"><p class="hint-container-title">注意</p><p>卸载应用不会删除 PDF 文件和批注文件。</p></div><h2 id="仍然有问题" tabindex="-1"><a class="header-anchor" href="#仍然有问题"><span>仍然有问题？</span></a></h2><p>如果以上内容没有解决您的问题，请：</p><ol><li>查看 <a href="https://github.com/LouisLu010/PdfTeachAnnotator/issues" target="_blank" rel="noopener noreferrer">GitHub Issues</a> 中是否有相同问题</li><li>创建新的 Issue 详细描述您的问题</li><li>提供以下信息： <ul><li>Windows 版本</li><li>应用版本</li><li>问题的详细描述</li><li>重现步骤</li><li>错误截图（如果有）</li></ul></li></ol><p>我们会尽快回复并帮助您解决问题。</p>',108)])])}const p=i(s,[["render",t]]),h=JSON.parse('{"path":"/guide/faq.html","title":"常见问题","lang":"zh-CN","frontmatter":{},"headers":[{"level":2,"title":"安装问题","slug":"安装问题","link":"#安装问题","children":[{"level":3,"title":"提示缺少 .NET Runtime","slug":"提示缺少-net-runtime","link":"#提示缺少-net-runtime","children":[]},{"level":3,"title":"安装失败","slug":"安装失败","link":"#安装失败","children":[]}]},{"level":2,"title":"使用问题","slug":"使用问题","link":"#使用问题","children":[{"level":3,"title":"无法打开 PDF 文件","slug":"无法打开-pdf-文件","link":"#无法打开-pdf-文件","children":[]},{"level":3,"title":"批注无法保存","slug":"批注无法保存","link":"#批注无法保存","children":[]},{"level":3,"title":"批注消失了","slug":"批注消失了","link":"#批注消失了","children":[]},{"level":3,"title":"窗口最大化后批注消失","slug":"窗口最大化后批注消失","link":"#窗口最大化后批注消失","children":[]},{"level":3,"title":"绘制的线条不流畅","slug":"绘制的线条不流畅","link":"#绘制的线条不流畅","children":[]},{"level":3,"title":"橡皮擦无法擦除","slug":"橡皮擦无法擦除","link":"#橡皮擦无法擦除","children":[]}]},{"level":2,"title":"性能问题","slug":"性能问题","link":"#性能问题","children":[{"level":3,"title":"应用启动慢","slug":"应用启动慢","link":"#应用启动慢","children":[]},{"level":3,"title":"打开大型 PDF 很慢","slug":"打开大型-pdf-很慢","link":"#打开大型-pdf-很慢","children":[]},{"level":3,"title":"缩放时卡顿","slug":"缩放时卡顿","link":"#缩放时卡顿","children":[]}]},{"level":2,"title":"数据问题","slug":"数据问题","link":"#数据问题","children":[{"level":3,"title":"如何备份批注","slug":"如何备份批注","link":"#如何备份批注","children":[]},{"level":3,"title":"如何迁移到新电脑","slug":"如何迁移到新电脑","link":"#如何迁移到新电脑","children":[]},{"level":3,"title":"如何导出批注","slug":"如何导出批注","link":"#如何导出批注","children":[]}]},{"level":2,"title":"兼容性问题","slug":"兼容性问题","link":"#兼容性问题","children":[{"level":3,"title":"支持哪些 PDF 版本","slug":"支持哪些-pdf-版本","link":"#支持哪些-pdf-版本","children":[]},{"level":3,"title":"支持触摸屏吗","slug":"支持触摸屏吗","link":"#支持触摸屏吗","children":[]},{"level":3,"title":"支持触控笔吗","slug":"支持触控笔吗","link":"#支持触控笔吗","children":[]}]},{"level":2,"title":"其他问题","slug":"其他问题","link":"#其他问题","children":[{"level":3,"title":"如何反馈问题","slug":"如何反馈问题","link":"#如何反馈问题","children":[]},{"level":3,"title":"如何获取更新","slug":"如何获取更新","link":"#如何获取更新","children":[]},{"level":3,"title":"应用是否收费","slug":"应用是否收费","link":"#应用是否收费","children":[]},{"level":3,"title":"隐私和安全","slug":"隐私和安全","link":"#隐私和安全","children":[]},{"level":3,"title":"如何卸载","slug":"如何卸载","link":"#如何卸载","children":[]}]},{"level":2,"title":"仍然有问题？","slug":"仍然有问题","link":"#仍然有问题","children":[]}],"git":{"updatedTime":null},"filePathRelative":"guide/faq.md"}');export{p as comp,h as data};
